text:
#define __TEST__

#include <stdio.h>

#ifdef __TEST__
#include <conio.h>
#include <stdlib.h>
#endif
#define STACKSIZE 64


int stack[STACKSIZE];
static int stack_ptr=0;

void overflow_test( int pos )
{
if( pos >= STACKSIZE )
{
puts( "Stack overflow!&#92;n" );
exit(1);
}
}

void underflow_test( int pos )
{
if( pos < 0 )
{
puts( "Stack underflow!&#92;n" );
exit(1);
}
}

void push( int value )
{
overflow_test( stack_ptr+1 );
stack[stack_ptr++] = value;
}

int pop( void )
{
underflow_test( --stack_ptr );
return stack[stack_ptr];
}

#ifdef __TEST__

void wait4keypress( void )
{
while( !kbhit())
;
}

int main( void )
{
atexit(wait4keypress); 
push(1);
push(2);
push(3);
printf( "%d&#92;n", pop());
printf( "%d&#92;n", pop());
printf( "%d&#92;n", pop());
/* must cause stack underflow */
printf( "%d&#92;n", pop());
return 0;
}

#endif  /* __TEST__ */

